const authLoginTimeout = 3 * time.Minute

var defaultOAuthCredentialsPath = googleCredentialsPath("calendar-tasks-oauth-client.json")

func googleCredentialsPath(filename string) string {
	configDir, err := os.UserConfigDir()
	if err != nil {
		home, homeErr := os.UserHomeDir()
		if homeErr != nil {
			return filename
		}
		configDir = filepath.Join(home, ".config")
	}
	return filepath.Join(configDir, "printing-press", "google-private", "credentials", filename)
}

