// newAuthSetupCmd prints concrete steps for registering an OAuth app and
// obtaining client credentials. Side-effect rule: print by default, --launch
// to open the registration URL, short-circuit when the verifier is running.
func newAuthSetupCmd(_ *rootFlags) *cobra.Command {
	var launch bool
	cmd := &cobra.Command{
		Use:     "setup",
		Short:   "Print steps for registering an OAuth app (use --launch to open the URL)",
		Example: "  google-calendar-pp-cli auth setup\n  google-calendar-pp-cli auth setup --launch",
		RunE: func(cmd *cobra.Command, args []string) error {
			w := cmd.OutOrStdout()
			fmt.Fprintln(w, "Create an OAuth Desktop app in Google Cloud Console:")
			fmt.Fprintln(w, "  https://console.cloud.google.com/apis/credentials")
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Save the Desktop client JSON at:")
			fmt.Fprintf(w, "  %s\n", defaultOAuthCredentialsPath)
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Then run one of:")
			fmt.Fprintln(w, "  google-calendar-pp-cli auth login")
			fmt.Fprintln(w, "  google-calendar-pp-cli auth login --no-browser")
			fmt.Fprintln(w, "  google-calendar-pp-cli auth login --manual")
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "For non-interactive token injection, use:")
			fmt.Fprintln(w, "  google-calendar-pp-cli auth set-token --token-json token.json")
			if !launch {
				return nil
			}
			launchURL := "https://console.cloud.google.com/apis/credentials"
			if cliutil.IsVerifyEnv() {
				fmt.Fprintf(w, "would launch: %s\n", launchURL)
				return nil
			}
			if err := openSetupURL(launchURL); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "could not open browser automatically: %v\nopen this URL manually: %s\n", err, launchURL)
			}
			return nil
		},
	}
	cmd.Flags().BoolVar(&launch, "launch", false, "Open the setup URL in your default browser")
	return cmd
}

// openSetupURL opens url in the OS default browser and returns any error
// from the launch. Distinct from openBrowser (used by `auth login`) because
// `auth setup --launch` prints a manual-fallback message on failure rather
// than silently failing. Per the side-effect rule, the caller short-circuits
// with cliutil.IsVerifyEnv() before this is reached.
func openSetupURL(url string) error {
	var c *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		c = exec.Command("open", url)
	case "linux":
		c = exec.Command("xdg-open", url)
	case "windows":
		c = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
	return c.Start()
}

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var clientID string
	var clientSecret string
	var port int
	var noBrowser bool
	var manual bool
	var credentialsFile string

	cmd := &cobra.Command{
		Use:   "login",
		Short: "Authenticate via OAuth2",
		RunE: func(cmd *cobra.Command, args []string) error {
			// PATCH: Read official Google OAuth Desktop app JSON by default and
			// expose --no-browser/--manual flows for WSL and headless agents.
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				// PATCH: Let auth repair malformed token TOML created by manual shell writes.
				fmt.Fprintf(cmd.ErrOrStderr(), "warning: ignoring unreadable config and rewriting it after successful auth: %v\n", err)
				cfg = config.Default(flags.configPath)
			}
			creds, err := loadOAuthDesktopCredentials(credentialsFile)
			if err != nil {
				return err
			}
			if clientID == "" {
				clientID = creds.ClientID
			}
			if clientSecret == "" {
				clientSecret = creds.ClientSecret
			}
			if cfg.AuthorizationURL == "" && creds.AuthorizationURL != "" {
				cfg.AuthorizationURL = creds.AuthorizationURL
			}
			if cfg.TokenURL == "" && creds.TokenURL != "" {
				cfg.TokenURL = creds.TokenURL
			}
			if clientID == "" {
				return fmt.Errorf("--client-id is required or provide OAuth Desktop credentials at %s", credentialsFile)
			}

			stateBytes := make([]byte, 16)
			if _, err := rand.Read(stateBytes); err != nil {
				return fmt.Errorf("generating state: %w", err)
			}
			state := hex.EncodeToString(stateBytes)

			listener, err := net.Listen("tcp", fmt.Sprintf("127.0.0.1:%d", port))
			if err != nil {
				return fmt.Errorf("starting callback server: %w", err)
			}
			defer listener.Close()

			callbackPort := listener.Addr().(*net.TCPAddr).Port
			redirectURI := fmt.Sprintf("http://localhost:%d/callback", callbackPort)

			authURL := ""
			authURL = cfg.AuthorizationURL
			if authURL == "" {
				authURL = "https://accounts.google.com/o/oauth2/v2/auth"
			}
			params := url.Values{
				"client_id":     {clientID},
				"redirect_uri":  {redirectURI},
				"response_type": {"code"},
				"state":         {state},
				"access_type":   {"offline"},
				"prompt":        {"consent"},
			}
			scopes := []string{"https://www.googleapis.com/auth/calendar", "https://www.googleapis.com/auth/calendar.events", "https://www.googleapis.com/auth/calendar.events.readonly", "https://www.googleapis.com/auth/calendar.readonly", "https://www.googleapis.com/auth/calendar.settings.readonly"}
			if len(scopes) > 0 {
				params.Set("scope", strings.Join(scopes, " "))
			}

			fullURL := authURL + "?" + params.Encode()
			out := cmd.OutOrStdout()
			fmt.Fprintf(out, "Callback port: %d\n", callbackPort)
			fmt.Fprintf(out, "Open this URL in your browser to authenticate:\n%s\n\n", fullURL)

			if manual {
				fmt.Fprintln(out, "Manual mode: open the URL yourself, then paste the full redirected localhost URL.")
			} else if noBrowser {
				fmt.Fprintln(out, "Browser open skipped because --no-browser was provided.")
			} else {
				fmt.Fprintf(out, "Opening browser for authentication...\n")
				if err := openBrowser(fullURL); err != nil {
					fmt.Fprintf(cmd.ErrOrStderr(), "could not open browser automatically: %v\n", err)
				}
			}

			codeCh := make(chan string, 1)
			errCh := make(chan error, 1)

			mux := http.NewServeMux()
			mux.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
				if r.URL.Query().Get("state") != state {
					sendAuthError(errCh, fmt.Errorf("state mismatch"))
					http.Error(w, "State mismatch", http.StatusBadRequest)
					return
				}
				if errMsg := r.URL.Query().Get("error"); errMsg != "" {
					sendAuthError(errCh, fmt.Errorf("auth error: %s", errMsg))
					http.Error(w, errMsg, http.StatusBadRequest)
					return
				}
				code := r.URL.Query().Get("code")
				if code == "" {
					sendAuthError(errCh, fmt.Errorf("no code in callback"))
					http.Error(w, "No code", http.StatusBadRequest)
					return
				}
				w.Header().Set("Content-Type", "text/html")
				if manual {
					fmt.Fprint(w, "<html><body><h2>OAuth redirect received.</h2><p>Copy the full localhost URL from the address bar and paste it into the terminal.</p></body></html>")
				} else {
					fmt.Fprint(w, "<html><body><h2>Authentication successful!</h2><p>You can close this tab.</p></body></html>")
				}
				sendAuthCode(codeCh, code)
			})

			server := &http.Server{Handler: mux}
			go server.Serve(listener)
			defer server.Shutdown(context.Background())

			var code string
			if manual {
				manualCode, err := readManualRedirectCode(cmd, state)
				if err != nil {
					return err
				}
				code = manualCode
			} else {
				fmt.Fprintf(out, "Waiting for Google OAuth callback on port %d...\n", callbackPort)
				select {
				case code = <-codeCh:
				case err := <-errCh:
					return err
				case <-time.After(authLoginTimeout):
					return fmt.Errorf("authentication timed out after 3 minutes")
				}
			}

			tokenURL := ""
			tokenURL = cfg.TokenURL
			if tokenURL == "" {
				tokenURL = "https://oauth2.googleapis.com/token"
			}
			tokenParams := url.Values{
				"grant_type":   {"authorization_code"},
				"code":         {code},
				"redirect_uri": {redirectURI},
				"client_id":    {clientID},
			}
			if clientSecret != "" {
				tokenParams.Set("client_secret", clientSecret)
			}

			resp, err := http.PostForm(tokenURL, tokenParams)
			if err != nil {
				return fmt.Errorf("exchanging code for token: %w", err)
			}
			defer resp.Body.Close()

			if resp.StatusCode >= 400 {
				var body map[string]any
				if err := json.NewDecoder(resp.Body).Decode(&body); err == nil {
					return fmt.Errorf("exchanging code for token: HTTP %d: %v", resp.StatusCode, body)
				}
				return fmt.Errorf("exchanging code for token: HTTP %d", resp.StatusCode)
			}

			var tokenResp struct {
				AccessToken  string `json:"access_token"`
				RefreshToken string `json:"refresh_token"`
				ExpiresIn    int    `json:"expires_in"`
				TokenType    string `json:"token_type"`
			}
			if err := json.NewDecoder(resp.Body).Decode(&tokenResp); err != nil {
				return fmt.Errorf("parsing token response: %w", err)
			}
			if tokenResp.AccessToken == "" {
				return fmt.Errorf("no access token in response")
			}

			// Guard against non-conformant servers that return expires_in: 0.
			// A zero-duration expiry resolves to time.Now(), which authHeader()
			// then treats as expired and triggers a refresh on every call.
			expiry := time.Time{}
			if tokenResp.ExpiresIn > 0 {
				expiry = time.Now().Add(time.Duration(tokenResp.ExpiresIn) * time.Second)
			}
			if err := cfg.SaveTokens(clientID, clientSecret, tokenResp.AccessToken, tokenResp.RefreshToken, expiry); err != nil {
				return fmt.Errorf("saving tokens: %w", err)
			}

			if expiry.IsZero() {
				fmt.Fprintf(os.Stderr, "%s Authentication successful! Token expiry not provided.\n", green("OK"))
			} else {
				fmt.Fprintf(os.Stderr, "%s Authentication successful! Token expires at %s\n", green("OK"), expiry.Format(time.RFC3339))
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&clientID, "client-id", os.Getenv("GOOGLE_CALENDAR_CLIENT_ID"), "OAuth2 client ID")
	cmd.Flags().StringVar(&clientSecret, "client-secret", os.Getenv("GOOGLE_CALENDAR_CLIENT_SECRET"), "OAuth2 client secret")
	cmd.Flags().IntVar(&port, "port", 8085, "Local callback server port")
	cmd.Flags().BoolVar(&noBrowser, "no-browser", false, "Print OAuth URL and wait for callback without opening a browser")
	cmd.Flags().BoolVar(&manual, "manual", false, "Print OAuth URL and paste the redirected localhost URL manually")
	cmd.Flags().StringVar(&credentialsFile, "credentials", defaultOAuthCredentialsPath, "OAuth Desktop client JSON path")

	return cmd
}

func newAuthSetTokenCmd(flags *rootFlags) *cobra.Command {
	var accessToken string
	var refreshToken string
	var clientID string
	var clientSecret string
	var expiresIn int
	var expiryText string
	var tokenJSON string

	cmd := &cobra.Command{
		Use:     "set-token",
		Short:   "Store OAuth tokens without hand-writing TOML",
		Example: "  google-calendar-pp-cli auth set-token --token-json token.json\n  cat token.json | google-calendar-pp-cli auth set-token --token-json -",
		RunE: func(cmd *cobra.Command, args []string) error {
			// PATCH: Keep shell quoting out of token persistence; this command
			// writes TOML through the config package instead of asking users to.
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				// PATCH: set-token is the repair path for malformed TOML.
				fmt.Fprintf(cmd.ErrOrStderr(), "warning: ignoring unreadable config and rewriting it: %v\n", err)
				cfg = config.Default(flags.configPath)
			}
			if tokenJSON != "" {
				token, err := readTokenJSON(cmd, tokenJSON)
				if err != nil {
					return err
				}
				if accessToken == "" {
					accessToken = token.AccessToken
				}
				if refreshToken == "" {
					refreshToken = token.RefreshToken
				}
				if expiresIn == 0 {
					expiresIn = token.ExpiresIn
				}
				if expiryText == "" {
					expiryText = firstNonEmpty(token.Expiry, token.TokenExpiry)
				}
				if clientID == "" {
					clientID = token.ClientID
				}
				if clientSecret == "" {
					clientSecret = token.ClientSecret
				}
			}
			if clientID == "" {
				clientID = cfg.ClientID
			}
			if clientSecret == "" {
				clientSecret = cfg.ClientSecret
			}
			if accessToken == "" {
				return fmt.Errorf("--access-token is required unless --token-json provides access_token")
			}
			expiry, err := resolveTokenExpiry(expiryText, expiresIn)
			if err != nil {
				return err
			}
			if err := cfg.SaveTokens(clientID, clientSecret, accessToken, refreshToken, expiry); err != nil {
				return fmt.Errorf("saving tokens: %w", err)
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config":      cfg.Path,
					"has_refresh": refreshToken != "",
					"expires":     expiryString(expiry),
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Saved OAuth token to %s\n", cfg.Path)
			if !expiry.IsZero() {
				fmt.Fprintf(cmd.OutOrStdout(), "Token expires at %s\n", expiry.Format(time.RFC3339))
			}
			if refreshToken == "" {
				fmt.Fprintf(cmd.ErrOrStderr(), "warning: no refresh token stored; run auth login when the access token expires\n")
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&accessToken, "access-token", "", "OAuth access token")
	cmd.Flags().StringVar(&refreshToken, "refresh-token", "", "OAuth refresh token")
	cmd.Flags().StringVar(&clientID, "client-id", os.Getenv("GOOGLE_CALENDAR_CLIENT_ID"), "OAuth2 client ID to store for refresh")
	cmd.Flags().StringVar(&clientSecret, "client-secret", os.Getenv("GOOGLE_CALENDAR_CLIENT_SECRET"), "OAuth2 client secret to store for refresh")
	cmd.Flags().IntVar(&expiresIn, "expires-in", 0, "Access token lifetime in seconds from now")
	cmd.Flags().StringVar(&expiryText, "expiry", "", "Absolute token expiry time in RFC3339 format")
	cmd.Flags().StringVar(&tokenJSON, "token-json", "", "OAuth token JSON file path, or '-' for stdin")
	return cmd
}

type oauthDesktopCredentials struct {
	ClientID         string
	ClientSecret     string
	AuthorizationURL string
	TokenURL         string
}

func loadOAuthDesktopCredentials(path string) (oauthDesktopCredentials, error) {
	var empty oauthDesktopCredentials
	if strings.TrimSpace(path) == "" {
		return empty, nil
	}
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return empty, nil
		}
		return empty, fmt.Errorf("reading OAuth credentials %s: %w", path, err)
	}
	var raw struct {
		Installed *struct {
			ClientID     string `json:"client_id"`
			ClientSecret string `json:"client_secret"`
			AuthURI      string `json:"auth_uri"`
			TokenURI     string `json:"token_uri"`
		} `json:"installed"`
		Web *struct {
			ClientID     string `json:"client_id"`
			ClientSecret string `json:"client_secret"`
			AuthURI      string `json:"auth_uri"`
			TokenURI     string `json:"token_uri"`
		} `json:"web"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return empty, fmt.Errorf("parsing OAuth credentials %s: %w", path, err)
	}
	if raw.Installed != nil {
		return oauthDesktopCredentials{
			ClientID:         raw.Installed.ClientID,
			ClientSecret:     raw.Installed.ClientSecret,
			AuthorizationURL: raw.Installed.AuthURI,
			TokenURL:         raw.Installed.TokenURI,
		}, nil
	}
	if raw.Web != nil {
		return oauthDesktopCredentials{
			ClientID:         raw.Web.ClientID,
			ClientSecret:     raw.Web.ClientSecret,
			AuthorizationURL: raw.Web.AuthURI,
			TokenURL:         raw.Web.TokenURI,
		}, nil
	}
	return empty, fmt.Errorf("OAuth credentials %s did not contain an installed Desktop app client", path)
}

type oauthTokenJSON struct {
	AccessToken  string `json:"access_token"`
	RefreshToken string `json:"refresh_token"`
	ExpiresIn    int    `json:"expires_in"`
	Expiry       string `json:"expiry"`
	TokenExpiry  string `json:"token_expiry"`
	ClientID     string `json:"client_id"`
	ClientSecret string `json:"client_secret"`
}

func readTokenJSON(cmd *cobra.Command, path string) (oauthTokenJSON, error) {
	var data []byte
	var err error
	if path == "-" {
		data, err = io.ReadAll(cmd.InOrStdin())
	} else {
		data, err = os.ReadFile(path)
	}
	if err != nil {
		return oauthTokenJSON{}, fmt.Errorf("reading token JSON: %w", err)
	}
	var token oauthTokenJSON
	if err := json.Unmarshal(data, &token); err != nil {
		return oauthTokenJSON{}, fmt.Errorf("parsing token JSON: %w", err)
	}
	return token, nil
}

func readManualRedirectCode(cmd *cobra.Command, state string) (string, error) {
	type lineResult struct {
		line string
		err  error
	}
	lineCh := make(chan lineResult, 1)
	go func() {
		reader := bufio.NewReader(cmd.InOrStdin())
		line, err := reader.ReadString('\n')
		if err != nil && err != io.EOF {
			lineCh <- lineResult{err: err}
			return
		}
		lineCh <- lineResult{line: strings.TrimSpace(line)}
	}()

	fmt.Fprintln(cmd.OutOrStdout(), "Paste redirected URL:")
	select {
	case result := <-lineCh:
		if result.err != nil {
			return "", fmt.Errorf("reading redirected URL: %w", result.err)
		}
		return codeFromRedirectURL(result.line, state)
	case <-time.After(authLoginTimeout):
		return "", fmt.Errorf("authentication timed out after 3 minutes waiting for redirected URL")
	}
}

func codeFromRedirectURL(rawURL string, state string) (string, error) {
	if strings.TrimSpace(rawURL) == "" {
		return "", fmt.Errorf("redirected URL was empty")
	}
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return "", fmt.Errorf("parsing redirected URL: %w", err)
	}
	query := parsed.Query()
	if errMsg := query.Get("error"); errMsg != "" {
		return "", fmt.Errorf("auth error: %s", errMsg)
	}
	if gotState := query.Get("state"); gotState != state {
		return "", fmt.Errorf("state mismatch")
	}
	code := query.Get("code")
	if code == "" {
		return "", fmt.Errorf("redirected URL did not include a code query parameter")
	}
	return code, nil
}

func resolveTokenExpiry(expiryText string, expiresIn int) (time.Time, error) {
	if strings.TrimSpace(expiryText) != "" {
		expiry, err := time.Parse(time.RFC3339, expiryText)
		if err != nil {
			return time.Time{}, fmt.Errorf("parsing --expiry: %w", err)
		}
		return expiry, nil
	}
	if expiresIn > 0 {
		return time.Now().Add(time.Duration(expiresIn) * time.Second), nil
	}
	return time.Time{}, nil
}

func expiryString(expiry time.Time) string {
	if expiry.IsZero() {
		return ""
	}
	return expiry.Format(time.RFC3339)
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if strings.TrimSpace(value) != "" {
			return value
		}
	}
	return ""
}

func sendAuthCode(ch chan<- string, code string) {
	select {
	case ch <- code:
	default:
	}
}

func sendAuthError(ch chan<- error, err error) {
	select {
	case ch <- err:
	default:
	}
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show authentication status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}

			w := cmd.OutOrStdout()
			authed := cfg.AccessToken != ""
			// JSON envelope: {authenticated, verified, source, config}.
			if flags.asJSON {
				out := map[string]any{
					"authenticated": authed,
					"verified":      false,
					"source":        cfg.AuthSource,
					"config":        cfg.Path,
				}
				return printJSONFiltered(w, out, flags)
			}

			if !authed {
				fmt.Fprintf(w, "  %s Not authenticated. Run 'auth login' to authenticate.\n", red("FAIL"))
				return nil
			}

			if cfg.TokenExpiry.IsZero() {
				fmt.Fprintf(w, "  %s Credentials present (not verified; no expiry info)\n", green("OK"))
			} else if time.Now().Before(cfg.TokenExpiry) {
				fmt.Fprintf(w, "  %s Credentials present (not verified; expires %s)\n", green("OK"), cfg.TokenExpiry.Format(time.RFC3339))
			} else {
				if cfg.RefreshToken != "" {
					fmt.Fprintf(w, "  %s Token expired (will auto-refresh on next request)\n", yellow("WARN"))
				} else {
					fmt.Fprintf(w, "  %s Token expired. Run 'auth login' to re-authenticate.\n", red("FAIL"))
				}
			}

			if cfg.AuthSource != "" {
				fmt.Fprintf(w, "  source: %s\n", cfg.AuthSource)
			}
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "logout",
		Short: "Remove stored authentication tokens",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			if err := cfg.ClearTokens(); err != nil {
				return fmt.Errorf("clearing tokens: %w", err)
			}
			// JSON envelope: {cleared: true}. The OAuth flavor does not
			// surface a "note" key because env-var creds aren't part of
			// this auth flow's contract.
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"cleared": true,
				}, flags)
			}
			fmt.Fprintf(os.Stderr, "Logged out. Tokens removed.\n")
			return nil
		},
	}
}

func openBrowser(url string) error {
	if isWSL() {
		if err := exec.Command("powershell.exe", "-NoProfile", "-Command", "Start-Process", url).Start(); err == nil {
			return nil
		}
	}
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		cmd = exec.Command("open", url)
	case "linux":
		cmd = exec.Command("xdg-open", url)
	case "windows":
		cmd = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
	return cmd.Start()
}

func isWSL() bool {
	if os.Getenv("WSL_DISTRO_NAME") != "" {
		return true
	}
	data, err := os.ReadFile("/proc/version")
	if err != nil {
		return false
	}
	return strings.Contains(strings.ToLower(string(data)), "microsoft")
}
